func buildTriageResults(txs []localTransaction, categoryNames map[string]string, limit int) []triageResult {
	ordered := append([]localTransaction(nil), txs...)
	sort.SliceStable(ordered, func(i, j int) bool {
		if ordered[i].Date.Equal(ordered[j].Date) {
			return ordered[i].ID > ordered[j].ID
		}
		return ordered[i].Date.After(ordered[j].Date)
	})

	results := make([]triageResult, 0)
	for _, tx := range ordered {
		if !isUnreviewedForTriage(tx) {
			continue
		}
		suggestedID, confidence := suggestTriageCategory(tx, txs)
		results = append(results, triageResult{
			ID:                    tx.ID,
			Payee:                 tx.Payee,
			Amount:                tx.Amount,
			Date:                  tx.DateString,
			CurrentCategoryID:     tx.CategoryID,
			SuggestedCategoryID:   suggestedID,
			SuggestedCategoryName: categoryNames[suggestedID],
			Confidence:            confidence,
		})
		if limit > 0 && len(results) >= limit {
			break
		}
	}
	return results
}

func isUnreviewedForTriage(tx localTransaction) bool {
	// PATCH(triage-parent-tier): align with the other counts predicates
	// (budget burn, subscription, duplicate, retag) by excluding split
	// parents, group parents, and group children. Without this gate a
	// single split or group receipt shows up once per child row plus a
	// duplicate for the parent total, polluting the inbox and skewing
	// suggested-category confidence.
	if tx.IsSplitParent || tx.IsGroupParent || tx.GroupParentID != "" {
		return false
	}
	return strings.EqualFold(tx.Status, "unreviewed")
}

func suggestTriageCategory(target localTransaction, txs []localTransaction) (string, float64) {
	counts := map[string]int{}
	total := 0
	for _, tx := range txs {
		if tx.PayeeNormalized != target.PayeeNormalized || !strings.EqualFold(tx.Status, "reviewed") || tx.CategoryID == "" {
			continue
		}
		if !target.Date.IsZero() && !tx.Date.IsZero() && !tx.Date.Before(target.Date) {
			continue
		}
		counts[tx.CategoryID]++
		total++
	}
	bestID, bestCount := "", 0
	for id, count := range counts {
		if count > bestCount || (count == bestCount && (bestID == "" || id < bestID)) {
			bestID, bestCount = id, count
		}
	}
	if total == 0 {
		return "", 0
	}
	return bestID, float64(bestCount) / float64(total)
}
